<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Tres Cadenas de Stablecoins — Oferta vs. Frecuencia de Pagos</text>
  <text x="20" y="50" fill="#a1a1aa" font-size="13" font-family="sans-serif">A mayo de 2026, Ethereum vs. Tron vs. Polygon</text>
  <rect x="430" y="18" width="12" height="12" fill="#38bdf8"/><text x="446" y="28" fill="#d4d4d8" font-size="13" font-family="sans-serif">Cuota de oferta</text>
