  <line x1="60" y1="345" x2="680" y2="345" stroke="rgba(255,255,255,.15)"/>
  <text x="140" y="368" fill="#d4d4d8" font-size="14" font-weight="700" text-anchor="middle" font-family="sans-serif">Ethereum</text>
  <rect x="90" y="240" width="45" height="105" fill="#38bdf8"/>
  <text x="112" y="230" fill="#38bdf8" font-size="13" font-weight="700" text-anchor="middle" font-family="sans-serif">52%</text>
